// oauth2-implicit-flow.js

class OAuth2Client {
  constructor(clientId, redirectUri) {
    this.clientId = clientId;
    this.redirectUri = redirectUri;
    this.accessToken = null;
  }

  authorize() {
    const authUrl = `https://authorization-server.com/oauth/authorize?response_type=token&client_id=${this.clientId}&redirect_uri=${encodeURIComponent(this.redirectUri)}&scope=read%20write`;
    window.location.href = authUrl;
  }

  parseAccessTokenFromUrl() {
    const hashParams = new URLSearchParams(window.location.hash.substring(1));
    if (hashParams.has('access_token')) {
      this.accessToken = hashParams.get('access_token');
      // Store the token in session storage for the duration of the session
      sessionStorage.setItem('accessToken', this.accessToken);
      return true;
    }
    return false;
  }

  getAccessToken() {
    if (!this.accessToken) {
      const storedToken = sessionStorage.getItem('accessToken');
      if (storedToken) {
        this.accessToken = storedToken;
      } else {
        console.error('Access token not found.');
      }
    }
    return this.accessToken;
  }

  async makeApiCall(url, method = 'GET', data = null) {
    const accessToken = this.getAccessToken();
    if (!accessToken) {
      throw new Error('No access token available.');
    }

    const headers = new Headers({
      'Authorization': `Bearer ${accessToken}`,
      'Content-Type': 'application/json'
    });

    const options = {
      method,
      headers,
      body: data ? JSON.stringify(data) : null
    };

    try {
      const response = await fetch(url, options);
      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }
      return await response.json();
    } catch (error) {
      console.error('API call failed:', error);
      throw error;
    }
  }
}

